import { useState, useEffect, useRef } from 'react';

/**
 * Custom hook to connect to Eulerstream WebSocket for TikTok Live Comments
 */
export const useEulerStream = (uniqueId) => {
  const [isConnected, setIsConnected] = useState(false);
  const [messages, setMessages] = useState([]);
  const [error, setError] = useState(null);
  
  const wsRef = useRef(null);
  const apiKey = "euler_YjdkM2FlMDQxZTk1NWU1OWM2MzM2MjRkNTgwYjI0Yjk0YWNhNTRjNzMzMTUyYzYyYzE3YzFi"; // Fixed Phase 1 API Key

  const connect = (id) => {
    // Determine which ID to use
    const targetId = id || uniqueId;
    if (!targetId) return;

    // Clean up existing connection if there is one
    if (wsRef.current) {
        wsRef.current.close();
    }

    try {
        const wsUrl = `wss://ws.eulerstream.com?uniqueId=${targetId}&apiKey=${apiKey}`;
        const ws = new WebSocket(wsUrl);

        ws.onopen = () => {
          setIsConnected(true);
          setError(null);
          // Clear previous messages when connecting to a new streamer
          setMessages([]); 
        };

        ws.onmessage = (event) => {
          try {
            const data = JSON.parse(event.data);
            
            if (data && data.messages && Array.isArray(data.messages)) {
              // Append new messages, keeping max 100 for performance
              setMessages(prev => {
                  const combined = [...prev, ...data.messages];
                  return combined.slice(-100);
              });
            }
          } catch (err) {
            console.error("Failed to parse websocket message", err);
          }
        };

        ws.onerror = (e) => {
            setError('WebSocket error occurred.');
            setIsConnected(false);
        };

        ws.onclose = () => {
            setIsConnected(false);
        };

        wsRef.current = ws;

    } catch (err) {
        setError(err.message || 'Failed to initialize connection');
        setIsConnected(false);
    }
  };

  const disconnect = () => {
      if (wsRef.current) {
          wsRef.current.close();
          wsRef.current = null;
          setIsConnected(false);
      }
  };

  // Optional: Auto-connect if uniqueId is provided on mount
  useEffect(() => {
    if (uniqueId) {
        connect(uniqueId);
    }
    return () => disconnect();
  }, []);

  return { isConnected, messages, error, connect, disconnect };
};

const { WebcastPushConnection } = require("tiktok-live-connector");

// ===== CONFIG =====
const STREAMER_USERNAME = "thanhdongian.dtt"; // <-- username livestream
const API_KEY = "euler_YjdkM2FlMDQxZTk1NWU1OWM2MzM2MjRkNTgwYjI0Yjk0YWNhNTRjNzMzMTUyYzYyYzE3YzFi";

// set API key cho Euler
process.env.EULER_API_KEY = API_KEY;

// ===== CONNECT =====
const tiktok = new WebcastPushConnection(STREAMER_USERNAME);

// connect livestream
tiktok.connect().then(state => {
    console.log("✅ Connected to room:", state.roomId);
}).catch(err => {
    console.error("❌ Connect failed:", err);
});


// ===== LISTEN COMMENTS =====
tiktok.on("chat", data => {
    const username = data.nickname;
    const comment = data.comment;

    console.log(`💬 ${username}: ${comment}`);

    // ===== AI AUTO REPLY PLACE =====
    autoReply(username, comment);
});


// ===== LIVE STATUS =====
tiktok.on("streamEnd", () => {
    console.log("🔴 Livestream ended.");
});


// ===== ERROR =====
tiktok.on("error", err => {
    console.error("⚠️ Error:", err);
});


// ===== AUTO REPLY FUNCTION =====
async function autoReply(user, message) {

    // ví dụ logic AI
    let reply = "";

    if (message.includes("giá")) {
        reply = "Sản phẩm đang giảm giá 20% hôm nay nhé!";
    } 
    else if (message.includes("ship")) {
        reply = "Shop hỗ trợ ship toàn quốc 🚚";
    } 
    else {
        return; // không trả lời nếu không match
    }

    console.log(`🤖 AI Reply -> ${user}: ${reply}`);

    // TODO: call API gửi reply
